module.render:
const body = sections[0] ? sections[0].trim() : '';
const href = (args.href && String(args.href).trim()) || '#';
const color = (args.color && String(args.color).trim()) || 'var(--accent-color)';
return '<a class="mdp-mod-button" href="' + href + '" style="background-color: ' + color + ';">' + body + '</a>';
